class Solution:
    def countPalindromes(self, s):
        from itertools import combinations
        MOD = 10**9 + 7
        n = len(s)
        count = 0
        for combo in combinations(range(n), 5):
            a, b, c, d, e = (s[i] for i in combo)
            if a == e and b == d:
                count += 1
        return count % MOD

