var countPalindromes = function(s) {
    const MOD = 1000000007n;
    const n = s.length;
    const idx = c => c.charCodeAt(0) - 48;
    const sufSingle = new Array(10).fill(0);
    const sufPair = Array.from({ length: 10 }, () => new Array(10).fill(0n));
    const sufPairSnap = new Array(n + 1);
    const snap = () => sufPair.map(row => row.slice());
    sufPairSnap[n] = snap();
    for (let i = n - 1; i >= 0; i--) {
        const a = idx(s[i]);
        for (let x = 0; x < 10; x++) sufPair[a][x] += BigInt(sufSingle[x]);
        sufSingle[a]++;
        sufPairSnap[i] = snap();
    }
    const preSingle = new Array(10).fill(0);
    const prePair = Array.from({ length: 10 }, () => new Array(10).fill(0n));
    let ans = 0n;
    for (let c = 0; c < n; c++) {
        const sp = sufPairSnap[c + 1];
        for (let a = 0; a < 10; a++) {
            for (let b = 0; b < 10; b++) {
                if (prePair[a][b] && sp[b][a]) {
                    ans = (ans + prePair[a][b] * sp[b][a]) % MOD;
                }
            }
        }
        const d = idx(s[c]);
        for (let x = 0; x < 10; x++) prePair[x][d] += BigInt(preSingle[x]);
        preSingle[d]++;
    }
    return Number(ans % MOD);
};
